item.content:encoded:
/* smaller padding for the whole website */

.container,
.container-fluid {
  padding-left: 1rem;
  padding-right: 1rem;
}

/* smaller padding for header*/

.header {
  padding: 0.5rem 0 ;
}

/* filter categories  */

.posts__tab-label, .posts-ajax__tab-label {
	font-size: 18px
}

.posts-ajax__row, .posts__categories-wrapper {justify-content: center; }

.posts__tab:hover .posts__tab-label, .posts-ajax__tab:hover .posts-ajax__tab-label, .posts__tab.checked .posts__tab-label, .posts-ajax__tab.checked .posts-ajax__tab-label {color: %#afafaf;}


/* blog post card body font size and colors */

.blog-post-type .post-card .post-card__body * {font-size: 18px}

.blog-post-type .post-card:hover .post-card__body {color: #afafaf;}

.blog-post-type .post-card:hover .post-card__body a {color: #afafaf;}

/* portfolio post card body font size and colors */

.portfolio-post-type .post-card .post-card__body {font-size: 18px}

.portfolio-post-type .post-card .post-card__heading {font-size: 18px}

.portfolio-post-type .post-card:hover .post-card__body {color: #afafaf;}

.portfolio-post-type .post-card:hover .post-card__body a {color: #afafaf;}

/* custom thinner separator */

.wp-block-separator {
  border-width: 1px;
}

/* blog post card 4 */

.blog-post-card-4 figure {
  margin-bottom: 0.25rem;
}
